## What to Build
The standardized collector interface that all upstream integrations implement. This is the heart of the data ingestion architecture.

## Core Trait Definition
```rust
// crates/vc_collect/src/lib.rs

use async_trait::async_trait;
use std::time::Duration;
use chrono::{DateTime, Utc};

/// All collectors implement this trait
#[async_trait]
pub trait Collector: Send + Sync {
    /// Unique identifier for this collector (e.g., "sysmoni", "caut", "ru")
    fn name(&self) -> &'static str;

    /// Schema version for output normalization
    fn schema_version(&self) -> u32;

    /// Perform collection with given context
    async fn collect(&self, ctx: &CollectContext) -> CollectResult;

    /// Default timeout for this collector
    fn default_timeout(&self) -> Duration {
        Duration::from_secs(30)
    }

    /// Whether this collector requires a specific tool on the target machine
    fn required_tool(&self) -> Option<&'static str> {
        None
    }
}

/// Context provided to collectors during collection
pub struct CollectContext {
    /// Which machine we're collecting from
    pub machine_id: MachineId,

    /// How to execute commands (local or SSH)
    pub executor: Box<dyn CommandExecutor>,

    /// Last cursor for incremental collection
    pub last_cursor: Option<Cursor>,

    /// Time window for incremental queries (e.g., "last 10 minutes")
    pub poll_window: Duration,

    /// Hard timeout for this collection
    pub timeout: Duration,

    /// Maximum bytes to read from command output
    pub max_bytes: usize,

    /// Maximum rows to insert
    pub max_rows: usize,
}

/// Result of a collection run
pub struct CollectResult {
    /// Normalized rows ready for DuckDB insertion
    pub rows: Vec<RowBatch>,

    /// Updated cursor for next poll (None = stateless)
    pub new_cursor: Option<Cursor>,

    /// Optional raw artifacts for debugging
    pub raw_artifacts: Vec<ArtifactRef>,

    /// Warnings to surface in UI
    pub warnings: Vec<Warning>,

    /// How long collection took
    pub duration: Duration,

    /// Whether collection succeeded
    pub success: bool,

    /// Error message if failed
    pub error: Option<String>,
}

/// Cursor types for different incremental patterns
#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum Cursor {
    /// For time-bounded queries (e.g., "since timestamp")
    Timestamp(DateTime<Utc>),

    /// For JSONL tail (inode + byte offset)
    FileOffset { inode: u64, offset: u64 },

    /// For SQLite incremental (last seen primary key)
    PrimaryKey(i64),

    /// For custom cursor formats
    Opaque(String),
}

/// Batch of rows for a single table
pub struct RowBatch {
    pub table: &'static str,
    pub rows: Vec<serde_json::Value>,
}

/// Warning to surface in UI
#[derive(Debug)]
pub struct Warning {
    pub level: WarningLevel,
    pub message: String,
    pub context: Option<String>,
}

#[derive(Debug)]
pub enum WarningLevel {
    Info,
    Warn,
    Error,
}
```

## Command Executor Trait
```rust
// crates/vc_collect/src/executor.rs

#[async_trait]
pub trait CommandExecutor: Send + Sync {
    /// Run a command and return stdout
    async fn run(&self, command: &str) -> Result<String, ExecutorError>;

    /// Run a command with timeout
    async fn run_timeout(&self, command: &str, timeout: Duration) -> Result<String, ExecutorError>;

    /// Read a file (or range of bytes)
    async fn read_file(&self, path: &str) -> Result<Vec<u8>, ExecutorError>;

    /// Read file from offset to end (for JSONL tail)
    async fn read_file_range(&self, path: &str, offset: u64) -> Result<Vec<u8>, ExecutorError>;

    /// Get file stat (inode, size)
    async fn stat(&self, path: &str) -> Result<FileStat, ExecutorError>;

    /// Run SQLite query
    async fn sqlite_query(&self, db_path: &str, query: &str) -> Result<Vec<serde_json::Value>, ExecutorError>;

    /// HTTP GET (for Prometheus scraping)
    async fn http_get(&self, url: &str) -> Result<String, ExecutorError>;
}

pub struct FileStat {
    pub inode: u64,
    pub size: u64,
    pub mtime: DateTime<Utc>,
}

/// Local executor (runs commands directly)
pub struct LocalExecutor;

/// SSH executor (runs commands via SSH)
pub struct SshExecutor {
    pub target: String,  // user@host:port
    pub timeout: Duration,
}
