## What to Build
The CLI entry point using clap, with robot mode output formatting for agent consumption.

## CLI Structure
```rust
// crates/vc_cli/src/lib.rs

use clap::{Parser, Subcommand};

#[derive(Parser)]
#[command(name = "vc")]
#[command(about = "Vibe Cockpit - Agent Fleet Command Center")]
#[command(version)]
pub struct Cli {
    #[command(subcommand)]
    pub command: Commands,

    /// Path to config file
    #[arg(short, long, global = true)]
    pub config: Option<PathBuf>,

    /// Increase verbosity
    #[arg(short, long, global = true, action = clap::ArgAction::Count)]
    pub verbose: u8,

    /// Quiet mode (errors only)
    #[arg(short, long, global = true)]
    pub quiet: bool,
}

#[derive(Subcommand)]
pub enum Commands {
    /// Start the TUI dashboard
    Ui {
        /// Refresh interval in seconds
        #[arg(short, long, default_value = "5")]
        interval: u64,
    },

    /// Start the web server
    Serve {
        /// Address to bind (default: 127.0.0.1:8080)
        #[arg(short, long, default_value = "127.0.0.1:8080")]
        bind: String,
    },

    /// Robot mode commands (agent-friendly JSON output)
    Robot {
        #[command(subcommand)]
        command: RobotCommands,
    },

    /// Run a single poll cycle
    Poll {
        /// Specific machine to poll (default: all)
        #[arg(short, long)]
        machine: Option<String>,

        /// Specific collector to run (default: all)
        #[arg(short, long)]
        collector: Option<String>,
    },

    /// Query DuckDB directly (read-only)
    Query {
        /// SQL query string
        sql: String,

        /// Output format
        #[arg(short, long, default_value = "table")]
        format: OutputFormat,
    },

    /// Watch mode (streaming events)
    Watch {
        /// Output format
        #[arg(short, long, default_value = "jsonl")]
        format: OutputFormat,

        /// Interval between checks (seconds)
        #[arg(short, long, default_value = "30")]
        interval: u64,
    },

    /// Database operations
    Db {
        #[command(subcommand)]
        command: DbCommands,
    },

    /// Show version and build info
    Version,
}

#[derive(Subcommand)]
pub enum RobotCommands {
    /// Overall health summary
    Health,

    /// Triage view (top issues + suggested commands)
    Triage,

    /// Machine details
    Machine {
        /// Machine ID
        id: String,
    },

    /// Account usage summary
    Accounts,

    /// Repository status
    Repos,

    /// Open alerts
    Alerts,

    /// Oracle predictions
    Oracle,

    /// Guardian healing status
    Guardian,

    /// Schema documentation
    Docs {
        #[command(subcommand)]
        which: RobotDocs,
    },
}

#[derive(Subcommand)]
pub enum RobotDocs {
    /// JSON schema documentation
    Schemas,
    /// Example outputs
    Examples,
}

#[derive(Subcommand)]
pub enum DbCommands {
    /// Run pending migrations
    Migrate,
    /// Vacuum and optimize
    Vacuum,
    /// Export to Parquet
    Export {
        /// Output directory
        #[arg(short, long)]
        output: PathBuf,
    },
}

#[derive(Clone, Copy, Debug, Default)]
pub enum OutputFormat {
    #[default]
    Table,
    Json,
    Jsonl,
    Csv,
}
