## Robot Output Envelope
```rust
// crates/vc_cli/src/robot.rs

use serde::Serialize;
use chrono::{DateTime, Utc};

/// Standard envelope for all robot output
#[derive(Serialize)]
pub struct RobotEnvelope<T: Serialize> {
    /// Schema identifier with version
    pub schema_version: String,

    /// When this output was generated
    pub generated_at: DateTime<Utc>,

    /// The actual data
    pub data: T,

    /// Data staleness (seconds since last collection per source)
    pub staleness: HashMap<String, u64>,

    /// Any warnings about data quality
    pub warnings: Vec<String>,
}

impl<T: Serialize> RobotEnvelope<T> {
    pub fn new(schema: &str, data: T) -> Self {
        Self {
            schema_version: schema.to_string(),
            generated_at: Utc::now(),
            data,
            staleness: HashMap::new(),
            warnings: vec![],
        }
    }

    pub fn with_staleness(mut self, staleness: HashMap<String, u64>) -> Self {
        self.staleness = staleness;
        self
    }

    pub fn with_warnings(mut self, warnings: Vec<String>) -> Self {
        self.warnings = warnings;
        self
    }

    pub fn to_json(&self) -> String {
        serde_json::to_string_pretty(self).unwrap_or_else(|e| {
            format!(r#"{{"error": "serialization failed: {}"}}"#, e)
        })
    }
}
```

