## Main Binary
```rust
// src/main.rs

use vc_cli::{Cli, Commands, RobotCommands};
use clap::Parser;

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    let cli = Cli::parse();

    // Setup logging based on verbosity
    let log_level = match cli.verbose {
        0 => "info",
        1 => "debug",
        _ => "trace",
    };
    tracing_subscriber::fmt()
        .with_env_filter(log_level)
        .init();

    // Load config
    let config = vc_config::VcConfig::load()?;

    match cli.command {
        Commands::Robot { command } => {
            let store = vc_store::Store::open_readonly(&config.vc.db_path)?;

            match command {
                RobotCommands::Health => {
                    let output = vc_cli::commands::robot_health(&store).await;
                    println!("{}", output.to_json());
                }
                // ... other robot commands
            }
        }
        Commands::Version => {
            println!("vc {} ({})", env!("CARGO_PKG_VERSION"), env!("VERGEN_GIT_SHA"));
        }
        _ => todo!("Command not yet implemented"),
    }

    Ok(())
}
